    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null, $skipEshop = false) {
        if ($isNew = $this->ID == null) {
            $this->CreatedDate = date('Y-m-d');
        }

        parent::save($conn);
        self::updateProductDateTime($this->ID);

        if ($isNew && !$skipEshop) {
            foreach (ModelEshop::getEshops() as $eshop) {
                $productEshop = new ProductEshop();
                $productEshop->Eshop_ID = $eshop->ID;
                $productEshop->Product_ID = $this->ID;
                $productEshop->Active = true;
                $productEshop->Vat_ID = $eshop->Vat_ID;
                $productEshop->save();
            }
        }
    }

    /**
     * @param int $productId
     * @param string $value
     */
    public static function updateProductDateTime(int $productId) {
        $query = Doctrine_Query::create();
        $query->update('Admin_Model_Product');
        $query->set('UpdateDateTime', '?', date('Y-m-d H:i:s'));
        $query->where('ID = ?', $productId);
        $query->execute();
    }

    public static function getActionProductsOnSlider(int $limit): array {
        $now = date('Y-m-d H:i:s');
        // Nejprve získáme všechny aktivní akční produkty
        $query = Doctrine_Query::create();
        $query->select('p.Product_ID, p.Price AS ActionPrice')
            ->from('Admin_Model_ProductEshop p')
            ->where('p.ProductPriceTypeCode = ?', PriceType::PRICE_ACTION)
            ->andWhere('p.Active = ?', true)
            ->andWhere('(p.ValidFrom IS NULL OR p.ValidFrom <= ?)', $now)
            ->andWhere('(p.ValidTo IS NULL OR p.ValidTo >= ?)', $now)
            ->orderBy('RAND()');

        $actionProducts = $query->execute();

        // Pro každý produkt zkontrolujeme, zda má akční cenu nižší než běžnou cenu
        $productIds = [];
        foreach ($actionProducts as $actionProduct) {
            $standardPriceQuery = Doctrine_Query::create()
                ->select('p.Price')
                ->from('Admin_Model_ProductEshop p')
                ->where('p.Product_ID = ?', $actionProduct->Product_ID)
                ->andWhere('p.ProductPriceTypeCode = ?', PriceType::PRICE_A);

            $standardProduct = $standardPriceQuery->fetchOne();

            if ($standardProduct && $actionProduct->ActionPrice < $standardProduct->Price) {
                $productIds[] = $actionProduct->Product_ID;

                // Ukončíme, pokud máme dostatek produktů
                if (count($productIds) >= $limit) {
                    break;
                }
            }
        }

        return self::getProductsByIDsForSlider($productIds);
    }



