    /**
     * @param string $searchTerm
     * @param int|null $limit
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getSearchProducts(string $searchTerm, int $limit = null, Eshop $eshop = null): array {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $userID = UserClientSession::getCurrentUserID();
        $searchTerm = utf2ascii($searchTerm);
        $searchArray = explode(' ', $searchTerm);

        $query = Doctrine_Query::create();
        $query->from("Admin_Model_Product product");
        $query->addSelect('product.*, productEshops.*, productStocks.*, vat.*, productLangs.*, productLangs.Name as ProductName, productImages.*, file.*, manufacturer.*, manufacturerFile.*');
        $query->addSelect('productLangs.Name as ProductName, productLangs.slug as slug, productLangs.Perex as Perex');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        if ($userID) {
            $query->addSelect('IF(productWatchDogs.ID, true, false) as Watchdog');
            $query->leftJoin('product.productWatchDogs productWatchDogs WITH productWatchDogs.User_ID =?', $userID);
        }
        $query->innerJoin('product.productEshops productEshops WITH productEshops.Eshop_ID = ? AND productEshops.Active = ?', [$eshop->ID, true]);
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('product.productStocks productStocks');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('product.categories categories');
        $query->leftJoin("product.manufacturer manufacturer");
        $query->leftJoin("manufacturer.manufacturerFile manufacturerFile");
        $query->leftJoin('product.parameters parameters WITH Parameter_ID = 14');
        $query->leftJoin('parameters.parameterValue parameterValue');
        $query->andWhere('productEshops.Price > 0');
//        $query->andWhere('productEshops.Active = ?', true);

        if ($searchTerm) {
            foreach ($searchArray as $search) {
                if (is_numeric(trim($search))) {
                    $query->andWhere('productLangs.Product_ID LIKE ?', '%' . trim($search) . '%');
                } else {
                    $query->andWhere('productLangs.SearchName LIKE ?', '%' . trim($search) . '%');
                    $query->orWhere('productLangs.Perex LIKE ?', '%' . trim($search) . '%');
                }
            }

            $query->orWhere('product.Code LIKE ?', '%' . $searchTerm . '%');
            $query->orWhere('product.EAN LIKE ?', '%' . $searchTerm . '%');
        }

        if ($limit != null)
            $query->limit($limit);

        $query->addGroupBy('product.ID');
        $query->addGroupBy('productEshops.ID');
        $products = $query->execute()->toArray();

        foreach ($products as &$product) {
            $productPrice = new ProductPrice($product, UserSettings::getInstance()->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts());
            $product = $productPrice->getProduct();
            $product['TotalQuantity'] = 0;
            foreach ($product['productStocks'] as &$productStock) {
                $product['TotalQuantity'] += $productStock['Quantity'];
            }
        }

        return $products;
    }

    /**
     * @param $searchTerm
     * @param Eshop|null $eshop
     * @return int
     */
    public static function getSearchProductsCount($searchTerm, Eshop $eshop = null): int {
        if (!$eshop)
