    /**
     * @param string $categoryIDs
     * @param ProductList $productList
     * @return array
     */
    public static function getProductsForCategory(string $categoryIDs, ProductList $productList): array {
        $eshop = Eshop::getInstance()->getEshop();
        $userID = UserClientSession::getCurrentUserID();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product object');
        $query->addSelect('object.*, productEshops.*, vat.*,productStocks.*, productLangs.*, productImages.*, file.*, manufacturer.*, manufacturerFile.*');
        $query->addSelect('productLangs.Name as ProductName, productLangs.slug as slug, productLangs.Perex as Perex');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        if ($userID) {
            $query->addSelect('IF(productWatchDogs.ID, true, false) as Watchdog');
            $query->leftJoin('object.productWatchDogs productWatchDogs WITH productWatchDogs.User_ID =?', $userID);
        }
        $query->leftJoin('object.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('object.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('object.productImages productImages');
        $query->leftJoin('object.productStocks productStocks');
//        $query->leftJoin('object.productImages productOtherImages WITH productOtherImages.Rank = true');
        $query->leftJoin("object.manufacturer manufacturer");
        $query->leftJoin("manufacturer.manufacturerFile manufacturerFile");
        $query->leftJoin('productImages.file file');
        $query->leftJoin('object.categories categories');
        $query->leftJoin('categories.category category');
        $query->leftJoin('object.parameters parameters WITH Parameter_ID = 14');
        $query->leftJoin('parameters.parameterValue parameterValue');
        $query->andWhere('productEshops.Price > ?', 0);
        $query->andWhereIn('category.ID', explode(',', $categoryIDs));

        if ($productList->getFilter()) {
            foreach ($productList->getFilter() as $filterParam => $values) {
                $query->leftJoin('object.parameters parameters' . $filterParam . ' WITH parameters' . $filterParam . '.Parameter_ID = ' . $filterParam);
                $query->andWhereIn('parameters' . $filterParam . '.ParameterValue_ID ', $values);
            }
        }

        if (sizeof($productList->getRangeFilter()) > 0) {
            foreach ($productList->getRangeFilter() as $parameterRange) {
                if ($parameterRange['Type'] === "Price") {
                    $query->leftJoin('object.productEshops productPriceA WITH productPriceA.ProductPriceTypeCode = ?', 'A');
                    $query->andWhere('productPriceA.Price >= ?', $parameterRange['From']);
                    $query->andWhere('productPriceA.Price <= ?', $parameterRange['To']);
                }
            }
        }

        $query->andWhere('productEshops.Active = ?', true);
        $query->addGroupBy('object.ID');
        $query->addGroupBy('productEshops.ID');
        $query->addGroupBy('productImages.ID');
        $query->orderBy(ProductList::getColumnBySorting($productList->getSorting()));
        $query->addOrderBy('productImages.Main DESC');
        $query->addOrderBy('productImages.Rank ASC');
        $query->limit(ProductList::DEFAULT_OFFSET);
        $query->offset(($productList->getPage() - 1) * ProductList::DEFAULT_OFFSET);
        $products = $query->execute()->toArray();

        foreach ($products as &$product) {
            $productPrice = new ProductPrice($product, UserSettings::getInstance()->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts());
            $product = $productPrice->getProduct();
            $product['TotalQuantity'] = 0;
            foreach ($product['productStocks'] as &$productStock) {
                $product['TotalQuantity'] += $productStock['Quantity'];
            }
        }

        return $products;
    }

