    /**
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getProductPinValueIDByProductID(int $productID, Eshop $eshop = null): int|null {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product product');
        $query->addSelect('product.ID, parameters.ParameterValue_ID as ParameterValue_ID');
        $query->leftJoin('product.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('product.parameters parameters WITH Parameter_ID = 11');
        $query->andWhere('product.ID = ?', $productID);
        $query->andWhere('productEshops.Active = ?', true);
        $query->addGroupBy('product.ID');
        $query->limit(1);
        return $query->fetchOne()->ParameterValue_ID;
    }

    /**
     * @param string $slug
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getProductBySlug(string $slug, Eshop $eshop = null): array {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $userID = UserClientSession::getCurrentUserID();

        $query = Doctrine_Query::create();
        $query->from("Admin_Model_Product product");
        $query->addSelect('product.*, productEshops.*, vat.*, manufacturerParam.ID, manufacturerParamValue.Value as ManufacturerParamValue, productStocks.*, stock.*, productLangs.*, categories.*, category.*, categoryLangs.*, manufacturer.*, manufacturerFile.*');
        $query->addSelect('productImages.*, file.*, parameters.*, parameter.*, parameterValue.*, parameterLangs.*');
        $query->addSelect('productEshops.Active as Active, productEshops.Discount as Discount');
        $query->addSelect('productLangs.Name as ProductName, productLangs.slug as slug, productLangs.Description as Description, productLangs.ShortDescription as ShortDescription, productLangs.Title as Title, productLangs.MetaDescription as MetaDescription');
        //$query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        if ($userID) {
            $query->addSelect('IF(productWatchDogs.ID, true, false) as Watchdog');
            $query->leftJoin('product.productWatchDogs productWatchDogs WITH productWatchDogs.User_ID =?', $userID);
        }
        $query->leftJoin('product.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('product.productStocks productStocks');
        $query->leftJoin('productStocks.stock stock');
        $query->leftJoin('product.parameters parameters');
        $query->leftJoin('parameters.parameter parameter');
        $query->leftJoin('parameter.parameterLangs parameterLangs WITH parameterLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('parameters.parameterValue parameterValue');
        $query->leftJoin('product.parameters manufacturerParam WITH manufacturerParam.Parameter_ID = 1');
        $query->leftJoin('manufacturerParam.parameterValue manufacturerParamValue');
        $query->leftJoin('product.manufacturer manufacturer');
        $query->leftJoin('manufacturer.manufacturerFile manufacturerFile');
        $query->leftJoin('product.categories categories');
        $query->leftJoin('categories.category category');
        $query->leftJoin('category.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->andWhere('productEshops.Active = ?', true);
        $query->andWhere('productEshops.Price > ?', 0);
        $query->andWhere('productLangs.slug = ?', $slug);
        $query->groupBy('product.ID, productEshops.ID');

        $product = $query->execute()->toArray();

        if (!$product)
            return [];

        $product[0]['TotalQuantity'] = 0;
        foreach ($product[0]['productStocks'] as &$productStock) {
            $product[0]['TotalQuantity'] += $productStock['Quantity'];
        }


        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product product');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        $query->leftJoin('product.categories categories');
        $query->where('product.ID = ?', $product[0]['ID']);
        $productCategories = $query->execute()->toArray();

        $product[0]['CategoryIDs'] = $productCategories[0]['CategoryIDs'];

        $productPrice = new ProductPrice($product[0], UserSettings::getInstance()->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts());

        return $productPrice->getProduct();
    }

