    public static function getProductByID(int $ID, Eshop $eshop = null, ?int $requiredQuantity = null): array {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product product');
        $query->addSelect('product.*, productEshops.*, vat.*, productStocks.*, productImages.*, file.*, productLangs.*, productLangs.Name as ProductName, categories.*');
        $query->addSelect('productLangs.Name as ProductName, productLangs.slug as slug');
        $query->addSelect('GROUP_CONCAT(categories.Category_ID SEPARATOR ",") as CategoryIDs');
        $query->leftJoin('product.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('product.categories categories');
        $query->leftJoin('product.productStocks productStocks');
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('productImages.file file');
        $query->where('product.ID = ?', $ID);
        $query->groupBy('product.ID, productEshops.ID');
        $query->limit(1);
        $product = $query->execute()->toArray();

        if (!$product)
            return [];

        $productPrice = new ProductPrice($product[0], UserSettings::getInstance()->getValue('Discount'), UserSettings::getInstance()->getGroupDiscounts(), $requiredQuantity);

        $product = $productPrice->getProduct();

        $product['TotalQuantity'] = 0;
        foreach ($product['productStocks'] as &$productStock) {
            $product['TotalQuantity'] += $productStock['Quantity'];
        }

        return $product;

    }

