    /**
     * @param array $cartItem
     */
    public static function updateStockAfterOrder(array $cartItem) {
        $product = self::getProductByID($cartItem['Product_ID'] ?? $cartItem['Product_Api_ID']);

        $newStockValue = $product['OnStock'] - $cartItem['Quantity'];
        $newStock = $newStockValue < 0 ? 0 : $newStockValue;

        $query = Doctrine_Query::create();
        $query->update('Admin_Model_Product');
        $query->set('OnStock', $newStock);
        $query->where("ID = ?", $product['ID']);
        $query->execute();

        self::updateProductDateTime($product['ID']);

        if (Admin_Model_ProductInCategory::isProductInSaleCategory($product['ID'])) {
            if ($newStock === 0) {
                Admin_Model_ProductEshop::removeAllDiscounts($product['ID']);
                Admin_Model_ProductInCategory::removeProductFromSaleCategory($product['ID']);
            }
        }

    }


    /**
     * @param Admin_Model_Order $order
     */
    public static function updateStockAfterOrderCancel(Admin_Model_Order $order): void {

        foreach ($order->orderItems as $orderItem) {
            $product = self::getProductByID($orderItem['Product_ID']);

            $newStockValue = $product['OnStock'] + $orderItem['Quantity'];

            $query = Doctrine_Query::create();
            $query->update('Admin_Model_Product');
            $query->set('OnStock', $newStockValue);
            $query->where("ID = ?", $product['ID']);
            $query->execute();

            self::updateProductDateTime($product['ID']);
        }

    }

    /**
     * @param Admin_Model_Order $order
     */
    public static function updateStockAfterOrderRestore(Admin_Model_Order $order): void {

        foreach ($order->orderItems as $orderItem) {
            $product = self::getProductByID($orderItem['Product_ID']);

            $newStockValue = $product['OnStock'] - $orderItem['Quantity'];

            $query = Doctrine_Query::create();
            $query->update('Admin_Model_Product');
            $query->set('OnStock', $newStockValue);
            $query->where("ID = ?", $product['ID']);
            $query->execute();

            self::updateProductDateTime($product['ID']);
        }


    }

    /**
     * @param ModelEshop|null $eshop
     * @return array|null
     * @throws Doctrine_Query_Exception
     */
    public static function getProductsForFeeds(?ModelEshop $eshop = null, array $forbiddenCategories = null): ?array {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product object');
        $query->addSelect('object.*, vat.*, productImages.*, file.*, productEshops.*, manufacturer.*');
        $query->addSelect('productLangs.Name Name, productLangs.slug slug');
        $query->addSelect('productLangs.Description Description, productLangs.ShortDescription ShortDescription');
        $query->addSelect('categories.*, subCategory.*, category.*');
        $query->addSelect('categoryLangs.*, subCategoryLangs.*');
        $query->addSelect('parameters.*, parameter.*, parameterValue.*, parameterLangs.*');
        $query->innerJoin("object.productEshops productEshops WITH productEshops.Eshop_ID = ?", $eshop->ID);
        $query->innerJoin("object.productLangs productLangs WITH productLangs.Language_ID = ?", $eshop->Language_ID);
        $query->leftJoin('object.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('object.manufacturer manufacturer');
        $query->leftJoin('object.categories categories');
        $query->leftJoin('categories.category category');
        $query->leftJoin('category.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('category.categoryEshops categoryEshops WITH categoryEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('category.category subCategory');
        $query->leftJoin('subCategory.categoryLangs subCategoryLangs WITH subCategoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('subCategory.categoryEshops subCategoryEshops WITH subCategoryEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('object.parameters parametersYear WITH Parameter_ID = 14');
        $query->leftJoin('object.parameters parameters');
        $query->leftJoin('parameters.parameter parameter');
        $query->leftJoin('parameter.parameterLangs parameterLangs WITH parameterLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('parameters.parameterValue parameterValue');
        $query->leftJoin('parametersYear.parameterValue parameterValueYear');
        $query->where('productEshops.Active = ?', true);
        $query->addWhere('subCategoryEshops.Active = ?', true);
        $query->addWhere('categoryEshops.Active = ?', true);
        if ($forbiddenCategories) {
            $query->whereNotIn('object.ID', Admin_Model_ProductInCategory::getProductIdsByCategoryIds($forbiddenCategories));
        }
        $products = $query->execute()->toArray();

        foreach ($products as &$product) {
            $productPrice = new ProductPrice($product, 0, []);
            $product = $productPrice->getProduct();
        }

        return $products;
    }


    /**
     * @param ModelEshop|null $eshop
     * @return array|null
     * @throws Doctrine_Query_Exception
     */
    public static function getProductsForAPI(?ModelEshop $eshop = null, array $productIDs = null, array $productCodes = null, int $offset = null, int $limit = null, string $sinceDate = null): ?array {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product object');
        $query->addSelect('object.*, vat.*, productImages.*, file.*, productEshops.*, manufacturer.*');
        $query->addSelect('productLangs.Name Name, productLangs.slug slug');
        $query->addSelect('productLangs.Description Description, productLangs.ShortDescription ShortDescription');
        $query->addSelect('categories.*, subCategory.*, category.*');
        $query->addSelect('categoryLangs.*, subCategoryLangs.*');
        $query->addSelect('parameters.*, parameter.*, parameterValue.*, parameterLangs.*');
        $query->innerJoin("object.productEshops productEshops WITH productEshops.Eshop_ID = ?", $eshop->ID);
        $query->innerJoin("object.productLangs productLangs WITH productLangs.Language_ID = ?", $eshop->Language_ID);
        $query->leftJoin('object.productImages productImages');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('productEshops.vat vat');
        $query->leftJoin('object.manufacturer manufacturer');
        $query->leftJoin('object.categories categories');
        $query->leftJoin('categories.category category');
        $query->leftJoin('category.categoryLangs categoryLangs WITH categoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('category.categoryEshops categoryEshops WITH categoryEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('category.category subCategory');
        $query->leftJoin('subCategory.categoryLangs subCategoryLangs WITH subCategoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('subCategory.categoryEshops subCategoryEshops WITH subCategoryEshops.Eshop_ID = ?', $eshop->ID);
        $query->leftJoin('object.parameters parameters');
        $query->leftJoin('parameters.parameter parameter');
        $query->leftJoin('parameter.parameterLangs parameterLangs WITH parameterLangs.Language_ID = ?', $eshop->Language_ID);
        $query->leftJoin('parameters.parameterValue parameterValue');
        $query->whereIn('productEshops.Active', [true, false]);
        if ($productIDs) {
            $query->andWhereIn('object.ID', $productIDs);
        }
        if ($productCodes) {
            $query->andWhereIn('object.Code', $productCodes);
        }
//        $query->addWhere('subCategoryEshops.Active = ?', true);
//        $query->addWhere('categoryEshops.Active = ?', true);
//
        if ($sinceDate) {
            $query->addWhere('object.UpdateDateTime >= ?', $sinceDate);
        }

        if ($limit) {
            $query->limit($limit);
        }

        if ($offset) {
            $query->offset($offset);
        }

//

        $products = $query->execute()->toArray();

        foreach ($products as &$product) {
            $productPrice = new ProductPrice($product, 0, []);
            $product = $productPrice->getProduct();
        }

        return $products;
    }


