    /**
     * @return array|null
     * @throws Doctrine_Query_Exception
     */
    public static function getProductsForPrice($sinceDate, $eshop = null): ?array {
        if ($eshop === null)
            $eshop = Eshop::getInstance()->getEshop();
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product object');
        $query->addSelect('object.ID, object.Code, productEshops.Price as PriceWithoutVat');
        $query->leftJoin('object.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);

        if ($sinceDate)
            $query->addWhere('object.UpdateDateTime >=?', $sinceDate);

        return $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
    }

    /**
     * @param $productId
     * @return mixed|null
     */
    public static function getProduct($productId): self|null {
        $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product object');
        if ($eshop) {
            $query->innerJoin('object.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
            $query->innerJoin('object.productLangs productLangs WITH productLangs.Language_ID = ?', $eshop->Language_ID);
            $query->leftJoin('productEshops.vat vat');
        }
        $query->where("object.ID = ?", $productId);
        $query->andWhere('object.Archived IS NOT TRUE');

        $product = $query->fetchOne();
        return $product ?: null;
    }

    public static function getTotalProductsForManufacturer($manufacturerID, Eshop $eshop = null): int {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Product object');
        $query->leftJoin('object.categories categories');
        $query->leftJoin('categories.category category');
        $query->leftJoin('object.productEshops productEshops WITH productEshops.Eshop_ID = ?', $eshop->ID);
        $query->andWhere('productEshops.Price > ?', 0);
        $query->andWhere('object.Manufacturer_ID=?', $manufacturerID);
        $query->andWhere('productEshops.Active = ?', true);

        return $query->count();
    }


